        [20,'Козерог'],[19,'Водолей'],[21,'Рыбы'],[20,'Овен'],
        [21,'Телец'],[21,'Близнецы'],[23,'Рак'],[23,'Лев'],
        [23,'Дева'],[23,'Весы'],[23,'Скорпион'],[22,'Стрелец']
    ];
    const [cut, sign] = signs[m - 1];
    return d < cut ? sign : signs[m % 12][1];
};

